import 'package:flutter_test/flutter_test.dart';

/// Shared behavior contract for generated IFS geometric construction module
/// smoke tests.
///
/// Owns only public module smoke expectations: constructor access, stable id,
/// shader path, well-formed presets, and metadata id consistency. It must not
/// know about individual fractal modules, rendering UI, app orchestration, or
/// shader implementation details.
void runModuleSmokeContract(
  String moduleName,
  Object Function() createModule, {
  required String expectedId,
  required String expectedShader,
}) {
  test('$moduleName instantiates', () {
    final dynamic module = createModule();
    expect(module.id, expectedId);
    expect(module.shader, expectedShader);
  });

  test('$moduleName presets are well-formed', () {
    final dynamic module = createModule();
    expect(module.presets, isNotEmpty);
    for (final dynamic preset in module.presets) {
      expect(preset.id, isNotEmpty);
      expect(preset.name, isNotEmpty);
    }
  });

  test('$moduleName metadata is consistent', () {
    final dynamic module = createModule();
    expect(module.metadata.id, module.id);
  });
}

